import { test, expect } from '@playwright/test';
import { fileURLToPath } from 'url';
import path from 'path';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/checkout.html')}`;

test.describe('Checkout Page', () => {
    test.beforeEach(async ({ page }) => {
        await page.goto(localUrl);
        await page.waitForLoadState('domcontentloaded');
    });

  test('should display initial state with all form elements and hidden confirmation', async ({ page }) => {
      const form = page.locator('form').first();
      await expect(form).toBeVisible();
      await expect(form.getByLabel(/name|full name/i)).toBeVisible();
      await expect(form.getByLabel(/address|street/i)).toBeVisible();
      await expect(form.getByLabel(/email|e-mail/i)).toBeVisible();
      await expect(page.locator('#confirmation, [data-testid="confirmation"]')).toBeHidden();
  });

  test('should allow filling all fields and submitting order', async ({ page }) => {
    const cardNumberInput = page.getByLabel('Card Number');
    const fullNameInput = page.getByLabel('Full Name');
    const emailInput = page.getByLabel('Email');
    const addressInput = page.getByLabel('Address');
    
    // Scoped locator to disambiguate the 'Submit Order' button
    const submitButton = page.locator('form').filter({ hasText: 'Card Number' }).getByRole('button', { name: 'Submit Order' });
    const confirmation = page.getByText('Thank you for your order.');

    await cardNumberInput.fill('4111 1111 1111 1111');
    await fullNameInput.fill('John Doe');
    await emailInput.fill('john@example.com');
    await addressInput.fill('123 Playwright St');
    await submitButton.click();

    await expect(confirmation).toBeVisible();
  });
});
